use std::cmp::min;

struct DfsContext {
    timer: usize,
    dfn: Vec<usize>,
    low: Vec<usize>,
    bridge_count: i32,
}

impl DfsContext {
    fn new(n: usize) -> Self {
        DfsContext {
            timer: 0,
            dfn: vec![0; n],
            low: vec![0; n],
            bridge_count: 0,
        }
    }
}

fn dfs(u: usize, p: isize, adj: &Vec<Vec<usize>>, ctx: &mut DfsContext) {
    ctx.timer += 1;
    ctx.dfn[u] = ctx.timer;
    ctx.low[u] = ctx.timer;

    for &v in &adj[u] {
        if v as isize == p {
            continue;
        }
        if ctx.dfn[v] != 0 {
            ctx.low[u] = min(ctx.low[u], ctx.dfn[v]);
        } else {
            dfs(v, u as isize, adj, ctx);
            ctx.low[u] = min(ctx.low[u], ctx.low[v]);
            if ctx.low[v] > ctx.dfn[u] {
                ctx.bridge_count += 1;
            }
        }
    }
}

